const crypto = require('crypto');
const body = $input.first().json.body || {};
const partnerCode = $vars.MOMO_PARTNER_CODE;
const accessKey = $vars.MOMO_ACCESS_KEY;
const secretKey = $vars.MOMO_SECRET_KEY;
const endpoint = $vars.MOMO_CREATE_ENDPOINT || 'https://payment.momo.vn/v2/gateway/api/create';
if (!partnerCode || !accessKey || !secretKey) {
  throw new Error('Missing MoMo vars');
}
const orderCode = String(body.orderCode || '').trim();
const amount = String(Number(body.amount || 0));
const requestId = `${orderCode}-${Date.now()}`;
const redirectUrl = String(body.returnUrl || 'https://calotrack-website.vercel.app/activate');
const ipnUrl = String($vars.MOMO_IPN_URL || '');
const orderInfo = `CaloTrack ${body.billingSku || 'order'} ${orderCode}`;
const extraData = body.phoneE164 ? Buffer.from(String(body.phoneE164)).toString('base64') : '';
const rawSignature = `accessKey=${accessKey}&amount=${amount}&extraData=${extraData}&ipnUrl=${ipnUrl}&orderId=${orderCode}&orderInfo=${orderInfo}&partnerCode=${partnerCode}&redirectUrl=${redirectUrl}&requestId=${requestId}&requestType=captureWallet`;
const signature = crypto.createHmac('sha256', secretKey).update(rawSignature).digest('hex');
return [{ json: { endpoint, requestBody: { partnerCode, accessKey, requestId, amount, orderId: orderCode, orderInfo, redirectUrl, ipnUrl, extraData, requestType: 'captureWallet', signature, lang: 'vi' } } }];
